// --- SPATIAL PARTITIONING (v45.8) ---
class SpatialHashGrid {
    constructor(bounds, dimensions) {
        const [x, z] = dimensions;
        this.cells = new Map();
        this.cellSize = 50; 
    }

    _getKey(x, z) {
        return `${Math.floor(x / this.cellSize)}:${Math.floor(z / this.cellSize)}`;
    }

    insert(mesh, box) {
        const minX = Math.floor(box.min.x / this.cellSize);
        const maxX = Math.floor(box.max.x / this.cellSize);
        const minZ = Math.floor(box.min.z / this.cellSize);
        const maxZ = Math.floor(box.max.z / this.cellSize);

        // FIX: Create the entry object ONCE. 
        // This ensures the Set in query() can properly deduplicate references.
        const entry = { mesh, box };

        for (let x = minX; x <= maxX; x++) {
            for (let z = minZ; z <= maxZ; z++) {
                const key = `${x}:${z}`;
                if (!this.cells.has(key)) {
                    this.cells.set(key, []);
                }
                this.cells.get(key).push(entry);
            }
        }
    }

    query(box) {
        const results = new Set();
        const minX = Math.floor(box.min.x / this.cellSize);
        const maxX = Math.floor(box.max.x / this.cellSize);
        const minZ = Math.floor(box.min.z / this.cellSize);
        const maxZ = Math.floor(box.max.z / this.cellSize);

        for (let x = minX; x <= maxX; x++) {
            for (let z = minZ; z <= maxZ; z++) {
                const key = `${x}:${z}`;
                const cell = this.cells.get(key);
                if (cell) {
                    for (const item of cell) {
                        results.add(item);
                    }
                }
            }
        }
        return results;
    }
}

